const mem = std.mem;

pub fn abbreviate(allocator: mem.Allocator, words: []const u8) mem.Allocator.Error![]u8 {
    // We'll iterate over the bytes.
    var letters = std.ArrayList(u8).init(allocator);
    var in_word = false;
    var first_char: u8 = 0;

    // Helper to check if byte is ASCII letter.
    const is_letter = @sum(bool, { byte: bytes[i], condition: @or(@and(@ge(byte, 'A'), @le(byte, 'Z')), @and(@ge(byte, 'a'), @le(byte, 'z')) });

    // Iterate.
    for (words) |byte| {
        if (is_letter(byte)) {
            // Convert to uppercase.
            var upper = if (byte >= 'a' and byte <= 'z') ? byte - 32 else byte;
            if (not in_word) {
                first_char = upper;
                in_word = true;
            }
        } else if (byte == '-' or byte == '_' or byte == ' ' or byte == '\t' or byte == '\n' or byte == '\r') {
            if (in_word) {
                letters.append(first_char);
                in_word = false;
            }
        } else {
            // Other punctuation: ignore.
        }
    }
    // End of input, finalize if still in word.
    if (in_word) {
        letters.append(first_char);
    }

    // Allocate result slice.
    const result_len = letters.items.len;
    const result = try allocator.alloc(u8, result_len);
    // Copy letters to result.
    for (letters.items, i: 0..) {
        result[i] = letters.items[i];
    }
    return result;
}

